package main

import (
	"fmt"
	"strings"
	"testing"
)

type Book struct {
	Title string
	ISBN  string
}

type ISBNService interface {
	FetchByISBN(isbn string) (*Book, error)
}

type mockService struct {
	calledISBN string
}

func (m *mockService) FetchByISBN(isbn string) (*Book, error) {
	m.calledISBN = isbn
	return &Book{Title: "Mocked Book", ISBN: isbn}, nil
}

func LookupBook(svc ISBNService, isbn string) (*Book, error) {
	return svc.FetchByISBN(isbn)
}

func TestLookupBook(t *testing.T) {
	mock := &mockService{}
	book, _ := LookupBook(mock, "978-000")

	if mock.calledISBN != "978-000" {
		t.Errorf("called with %s, want 978-000", mock.calledISBN)
	}
	if !strings.Contains(book.Title, "Mock") {
		t.Errorf("book title %q does not contain Mock", book.Title)
	}
	fmt.Println("ISBN mock test passed")
	fmt.Println("ISBN queried:", mock.calledISBN)
	fmt.Println("Book:", book.Title)
}

func main() {
	TestLookupBook(&testing.T{})
}

