import (
	"fmt"
	"testing"
)

type Book struct {
	Title string
	ISBN  string
}

type Library struct {
	Books []Book
}

func (l Library) lookupByISBN(isbn string) *Book {
	for _, b := range l.Books {
		if b.ISBN == isbn {
			return &b
		}
	}
	return nil
}

func assertFound(t *testing.T, lib Library, isbn, wantTitle string) {
	t.Helper()
	got := lib.lookupByISBN(isbn)
	if got == nil {
		t.Errorf("lookupByISBN(%q) returned nil, want book with title %q", isbn, wantTitle)
	} else if got.Title != wantTitle {
		t.Errorf("lookupByISBN(%q).Title = %q, want %q", isbn, got.Title, wantTitle)
	}
}

func TestLookup(t *testing.T) {
	lib := Library{Books: []Book{
		{"Go 101", "978-123"},
		{"Testing", "978-456"},
		{"Network Programming", "978-789"},
	}}
	assertFound(t, lib, "978-123", "Go 101")
	assertFound(t, lib, "978-456", "Testing")
	// TODO: assert looking up "978-789" gives "Network Programming"
	fmt.Println("All lookup tests passed")
}

func main() {
	TestLookup(&testing.T{})
}

